        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'b')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'w')

    def print_board(self):
        for row in self.board:
            for piece in row:
                if piece is None:
                    print('.', end=' ')
                elif piece.color == 'b':
                    print('b', end=' ')
                else:
                    print('w', end=' ')
