        moves = []
        x, y = from_pos
        if self.color == 'white':
            if x > 0 and (y > 0 and not board.get_piece((x-1, y-1))):
                moves.append((x-1, y-1))
            if x > 0 and (y < 7 and not board.get_piece((x-1, y+1))):
